export const incompleteTodos = () => {
    return (
    <div>
        <p>未完了のToDo</p>
        <ul>
          {incompleteTodos.map((todo, index) => (
          <li key={todo}>
            <p>{todo}</p>
            <button onClick={() => onClickComplete(index)}>完了</button>
            <button onClick={() => onClickDelete(index)}>削除</button>
          </li>
            )
          )}
        </ul>
    </div>
    )
}
